var e=[{id:`L2_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`하아…….`,JPN:`はあ……`,ENG:`*Sigh...*`,TWN:`哀……`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`어젠 이상한 손님이 오는 바람에 눈치만 보다가 엉겁결에 퇴근까지 해버렸네요.`,JPN:`昨日は変なお客様が来たせいで顔色を伺うばかりで、
あたふたするうちに仕事が終わってしまいました。`,ENG:`Last night, I got distracted by some strange customer. I totally forgot about what I was going to do until I got off work.`,TWN:`都是因為昨天那個奇怪的客人，害我提早下班。`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`하지만, 오늘에야말로 악마와 담판을 짓겠어요!`,JPN:`ですが、今日こそ悪魔と決着をつけます！`,ENG:`But not today. I'm going to finish that devil, no matter what!`,TWN:`今天一定要跟魔鬼做個了結！`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`…응?`,JPN:`……あれ？`,ENG:`Hmm?`,TWN:`…嗯？`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`뒤처리는 제대로 했겠지?`,JPN:`後始末は問題ないな？`,ENG:`You took care of everything, right?`,TWN:`都有處理乾淨吧？`},stage:{bg:`BAR_ENTRY_02`,slots:{L:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_B`,text:{KOREA:`그래, 그 여자 완전히 곯아떨어져서 아무것도 모르던데?`,JPN:`もちろん。あの女、完全に酔いつぶれて何も気づいてなかったぞ。`,ENG:`Of course. She was so drunk, she had no idea.`,TWN:`那當然，那女的完全醉得不省人事！`},stage:{bg:`BAR_ENTRY_02`,slots:{L:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`},C:null,R:{char_id:`BARTENDER_NPC_POISONRAT_B`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_B`,text:{KOREA:`방에 술 냄새가 어찌나 심하게 진동을 하던지. 코가 마비되는 줄 알았다니까.`,JPN:`店内の酒の臭いが本当にすごいな。鼻が麻痺するかと思ったぞ。`,ENG:`The whole place smelled of alcohol. I couldn't breathe!`,TWN:`房裡的酒味濃到我以為我的鼻子會壞掉。`},stage:{bg:`BAR_ENTRY_02`,slots:{L:{char_id:`BARTENDER_NPC_POISONRAT_B`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`BARTENDER_NPC_POISONRAT_A`,text:{KOREA:`좋아. 돌아가는 대로 보스한테 보고하자고.`,JPN:`よし、戻り次第ボスに報告しよう。`,ENG:`Alright, let's report back to the Boss.`,TWN:`很好，趕快回去報告老大吧！`},stage:{bg:`BAR_ENTRY_02`,slots:{L:{char_id:`BARTENDER_NPC_POISONRAT_B`,face:`UNIT_IDLE`},C:null,R:{char_id:`BARTENDER_NPC_POISONRAT_A`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`휴, 하마터면 마주칠 뻔했어요.`,JPN:`ふう、危うく出くわすところでした。`,ENG:`Whew! Thank God, they didn't see me.`,TWN:`呼，差點就撞到他們。`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`저 복장은 분명… 제가 얼마 전에 마주쳤던 죄인들이네요.`,JPN:`あの服装は確か……私がこの前出会った罪人たちですね。`,ENG:`Their clothes... They're the sinners I encountered a while ago.`,TWN:`看他們那身造型…就是我之前遇到的那些壞蛋吧！`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`그런데 어째서 저희 가게에서 나온 걸까요?`,JPN:`なぜうちの店に来たのでしょう？`,ENG:`And why did they come out of my shop?`,TWN:`不過他們為什麼會從我們店裡走出來？`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`설마… 그레모리 씨에게 나쁜 짓을 저지르기라도 한 건?!`,JPN:`まさか……グレモリーさんに何か悪いことを！？`,ENG:`Oh, no! What if they hurt Gremory?`,TWN:`難道…他們該不會對葛茉莉不利吧？`},stage:{bg:`BAR_ENTRY_02`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`그레모리 씨!`,JPN:`グレモリーさん！`,ENG:`Gremory!`,TWN:`葛茉莉！`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`으음…`,JPN:`ううん……`,ENG:`Mm...`,TWN:`嗯…`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`테이블에 처참하게 널브러져 계신 그레모리 씨…`,JPN:`テーブルの上で無防備な状態で泥酔しているグレモリーさん……`,ENG:`Gremory is sprawled half across the table...`,TWN:`狼狽地攤在桌下的葛茉莉…`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`BARTENDER_BAR_NULL_NULL`,text:{KOREA:`다행히 평소 모습 그대로예요.`,JPN:`よかった、いつもと同じです。`,ENG:`As usual. Thank God!`,TWN:`完全跟平常一樣呢，好險！`},stage:{bg:`GREMORY_BAR`,slots:{L:null,C:{char_id:`BARTENDER_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};